import{_ as a,o as t,c as i,ag as n}from"./chunks/framework.Lq6hU67C.js";const u=JSON.parse('{"title":"Leak definition and severity","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/leak-definition-and-severity.md","filePath":"concepts/leak-definition-and-severity.md"}'),s={name:"concepts/leak-definition-and-severity.md"};function o(r,e,l,d,h,c){return t(),i("div",null,[...e[0]||(e[0]=[n(`<h1 id="leak-definition-and-severity" tabindex="-1">Leak definition and severity <a class="header-anchor" href="#leak-definition-and-severity" aria-label="Permalink to &quot;Leak definition and severity&quot;">​</a></h1><p>Addressables Leak Detector uses a <strong>passive</strong> model by default: it lists live handles without auto-alarming. Severity heuristics help you prioritize investigation.</p><h2 id="what-counts-as-a-leak-here" tabindex="-1">What counts as a &quot;leak&quot; here <a class="header-anchor" href="#what-counts-as-a-leak-here" aria-label="Permalink to &quot;What counts as a &quot;leak&quot; here&quot;">​</a></h2><p>A <strong>live handle</strong> is an Addressables operation that was loaded (recorded by Layer 1) and not yet released (no matching release record removed it from the live registry).</p><p>This is not a definitive memory leak verdict — it is <strong>evidence that a Release call may be missing</strong> at the call site shown in the leak trace.</p><h2 id="severity-levels" tabindex="-1">Severity levels <a class="header-anchor" href="#severity-levels" aria-label="Permalink to &quot;Severity levels&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Severity</th><th>Meaning</th><th>UI color</th></tr></thead><tbody><tr><td><strong>Normal</strong></td><td>Live handle; no heuristic triggered</td><td>Grey</td></tr><tr><td><strong>Aging</strong></td><td>Lives longer than 1.5× median for same call site (&gt;1 s)</td><td>Yellow</td></tr><tr><td><strong>RedundantLoad</strong></td><td>Same asset loaded again while a prior handle is still live</td><td>Orange</td></tr><tr><td><strong>SceneSurvivor</strong></td><td>Handle survived a <strong>non-additive</strong> scene change without Release</td><td>Red</td></tr></tbody></table><h3 id="scenesurvivor-high-confidence" tabindex="-1">SceneSurvivor (high confidence) <a class="header-anchor" href="#scenesurvivor-high-confidence" aria-label="Permalink to &quot;SceneSurvivor (high confidence)&quot;">​</a></h3><p>The only heuristic treated as high-confidence for &quot;forgot to release before scene transition.&quot; See <a href="./../how-to/scene-survival-heuristic.html">Scene survival heuristic</a>.</p><h3 id="aging-and-redundantload-informational" tabindex="-1">Aging and RedundantLoad (informational) <a class="header-anchor" href="#aging-and-redundantload-informational" aria-label="Permalink to &quot;Aging and RedundantLoad (informational)&quot;">​</a></h3><p>Useful for spotting slow leaks or duplicate loads; not automatic false-positive alarms. Long-lived startup preloads may appear yellow — use allowlisting if intentional.</p><h2 id="intentionally-persistent-handles" tabindex="-1">Intentionally persistent handles <a class="header-anchor" href="#intentionally-persistent-handles" aria-label="Permalink to &quot;Intentionally persistent handles&quot;">​</a></h2><p>Mark known long-lived loads with:</p><div class="language-csharp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">AddressablesIntentionallyPersistent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">void</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> PreloadAtStartup</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() { </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">..</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">. }</span></span></code></pre></div><p>Or ignore call-site patterns in the Editor (see <a href="./../how-to/allowlist-and-persistent-handles.html">Allowlist and persistent handles</a>).</p><h2 id="out-of-scope" tabindex="-1">Out of scope <a class="header-anchor" href="#out-of-scope" aria-label="Permalink to &quot;Out of scope&quot;">​</a></h2><ul><li>Engine-internal Addressables retention (Unity keeps assets alive internally — not a missing user <code>Release</code>).</li><li>Handles loaded in assemblies excluded from ILPP.</li><li>Runtime builds (Editor-focused tool; ILPP applies to Editor script compilation).</li></ul><h2 id="roadmap-tabs-not-in-mvp" tabindex="-1">Roadmap tabs (not in MVP) <a class="header-anchor" href="#roadmap-tabs-not-in-mvp" aria-label="Permalink to &quot;Roadmap tabs (not in MVP)&quot;">​</a></h2><p>Future releases may add <strong>Health Graph</strong> (ref-count trends) and <strong>Snapshot Diff</strong> (baseline compare). Current release: <strong>Live Leaks</strong> tab only.</p>`,19)])])}const g=a(s,[["render",o]]);export{u as __pageData,g as default};
